#!/usr/bin/env bash
set -euo pipefail

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
SRC_DIR="$ROOT_DIR/src"
OUT_FILE="$SRC_DIR/WCPLGestureHook.xm"
TMP_FILE="$(mktemp)"

cleanup() {
  rm -f "$TMP_FILE"
}
trap cleanup EXIT

cat > "$TMP_FILE" <<'HEADER'
// AUTO-GENERATED FILE.
// Source modules (stitched in fixed order):
// - WCPLGesturePureHelpers.xm
// - WCPLGestureDebugHelpers.xm
// - WCPLGestureHookCommon.xm
// - WCPLGestureRepeatEligibilityHelpers.xm
// - WCPLGestureCellContextHelpers.xm
// - WCPLGestureLayoutHelpers.xm
// - WCPLRepeatButtonHook.xm
// - WCPLMessageTimeHook.xm
// - WCPLSwipeQuoteHook.xm
// - WCPLRepeatActionHook.xm
// - WCPLDoubleTapHook.xm
//
// WCPLGestureHook.xm is a generated aggregation artifact.
// Do not edit this file manually. Edit module files and rerun:
//   scripts/generate_wcpl_gesture_hook.sh
HEADER

append_module() {
  local module="$1"
  printf '\n// ===== %s =====\n\n' "$module" >> "$TMP_FILE"
  printf '#line 1 "%s/%s"\n' "src" "$module" >> "$TMP_FILE"
  cat "$SRC_DIR/$module" >> "$TMP_FILE"
  printf '\n' >> "$TMP_FILE"
}

append_module "WCPLGesturePureHelpers.xm"
append_module "WCPLGestureDebugHelpers.xm"
append_module "WCPLGestureHookCommon.xm"
append_module "WCPLGestureRepeatEligibilityHelpers.xm"
append_module "WCPLGestureCellContextHelpers.xm"
append_module "WCPLGestureLayoutHelpers.xm"
append_module "WCPLRepeatButtonHook.xm"
append_module "WCPLMessageTimeHook.xm"
append_module "WCPLSwipeQuoteHook.xm"
append_module "WCPLRepeatActionHook.xm"
append_module "WCPLDoubleTapHook.xm"

if cmp -s "$TMP_FILE" "$OUT_FILE" 2>/dev/null; then
  exit 0
fi

mv "$TMP_FILE" "$OUT_FILE"
echo "[wcpl] regenerated src/WCPLGestureHook.xm"
